import Deepgram from 'deepgram-sdk';
import { Vex } from '@vex_dev/sdk';

const deepgram = new Deepgram(process.env.DEEPGRAM_KEY);
const vex = new Vex({ projectId: 'voice-agent' });

async function* sttStream(audioStream: ReadableStream) {
  const deepgramStream = deepgram.transcription.live({
    punctuate: true,
    interim_results: true
  });

  for await (const transcription of deepgramStream) {
    const result = await vex.verify({
      input: transcription.channel.alternatives[0].transcript,
      checks: [
        'length < 200', // Prevent verbose transcripts
        'no_hate_speech',
        'latency < 150ms'
      ]
    });

    if (result.passed) {
      yield {
        transcript: result.output,
        confidence: transcription.channel.alternatives[0].confidence,
        timestamp: Date.now()
      };
    }
  }
}

import { AgentExecutor } from 'mastra/agents';
import { VexGuardrail } from '@vex_dev/sdk';

const reasoningAgent = new AgentExecutor({
  model: 'gpt-4o-mini',
  tools: [getUserCalendar, checkWeather],
  maxIterations: 3
});

const latencyGuardrail = new VexGuardrail({
  name: 'voice-reasoning-latency',
  checks: {
    responseTime: { lt: 300, unit: 'ms' },
    tokenUsage: { lt: 1500 },
    appropriateness: 'voice_conversation'
  }
});

export async function reason(transcript: string, context: ConversationMemory) {
  const start = performance.now();
  const response = await reasoningAgent.invoke({
    input: transcript,
    context,
    guardrails: [latencyGuardrail]
  });

  const latency = performance.now() - start;

  const verified = await vex.verify({
    input: response.output,
    metadata: { latency, contextRecency: context.lastUpdate }
  });

  return verified.output;
}

import { VectorStore } from 'mastra/memory';
import { Vex } from '@vex_dev/sdk';

const conversationMemory = new VectorStore({
  embeddingModel: 'text-embedding-3-small',
  collection: 'voice-sessions'
});

const vexMemoryGuard = new Vex({
  projectId: 'voice-agent',
  checks: ['semantic_similarity > 0.8', 'timestamp < 5m']
});

export async function retrieveContext(sessionId: string, query: string) {
  const results = await conversationMemory.similaritySearch(query, 5);

  const verifiedContext = await vexMemoryGuard.verify({
    input: results,
    criteria: {
      recency: { maxAge: 5 * 60 * 1000 }, // 5 minutes
      relevance: { threshold: 0.75 },
      coherence: 'ongoing_conversation'
    }
  });

  return verifiedContext.filter(ctx => ctx.passed);
}

