import { Workflow } from 'mastra/workflows';
import { VexMiddleware } from '@vex_dev/sdk';

const voicePipelineMiddleware = new VexMiddleware({
  projectId: 'mastra-voice-agent',
  riskProfile: 'high',
  defaultChecks: [
    'latency_budget:300ms',
    'safety_filter:strict',
    'json_schema_validation',
    'conversation_coherence'
  ]
});

// Apply to entire Mastra workflow
const voiceAgent = new Workflow({
  name: 'voice-agent-pipeline',
  middleware: [voicePipelineMiddleware],
  // ... rest of workflow config
});

// Per-node override for critical paths
voiceAgent.node('reasoning').middleware([
  voicePipelineMiddleware.enforce({
    maxLatency: 250,
    safetyLevel: 'strict'
  })
]);

import { VexSafetyFilter } from '@vex_dev/sdk';

const voiceSafetyFilter = new VexSafetyFilter({
  categories: ['hate_speech', 'violence', 'sexual_content'],
  voiceContext: true,
  fallbackResponses: [
    "I can't help with that request.",
    "Let me think of a better way to help you.",
    "That's not something I can discuss right now."
  ]
});

export async function safeTTSOutput(llmResponse: string): Promise<string> {
  const result = await voiceSafetyFilter.verify(llmResponse);

  if (!result.passed) {
    console.warn('Safety violation detected:', result.violations);
    return voiceSafetyFilter.getFallback(result.severity);
  }

  // Additional voice-specific checks
  const voiceChecks = await vex.verify({
    input: result.output,
    checks: ['no_repetition', 'natural_prosody', 'length < 120']
  });

  return voiceChecks.output;
}

import { VexMonitor } from '@vex_dev/sdk';

const latencyMonitor = new VexMonitor({
  pipeline: 'voice-agent',
  budget: {
    stt: 150,
    reasoning: 250,
    tts: 100,
    total: 500 // ms
  },
  alerts: {
    slack: process.env.SLACK_WEBHOOK,
    threshold: '95th_percentile'
  }
});

export async function monitoredPipeline(audio: Buffer, sessionId: string) {
  const spans = latencyMonitor.start('full_pipeline');

  spans.stt.start();
  const transcript = await stt(audio);
  spans.stt.end();

  spans.reasoning.start();
  const response = await reason(transcript, sessionId);
  spans.reasoning.end();

  spans.tts.start();
  const speech = await tts(response);
  spans.tts.end();

  const budgetCheck = await spans.complete();

  if (!budgetCheck.passed) {
    await latencyMonitor.alert({
      sessionId,
      actual: budgetCheck.metrics,
      budget: latencyMonitor.budget
    });
  }

  return speech;
}
